{
  "filecontent": null,
  "displayorder": 3,
  "pagetemplateid": "835852c9-4793-49e2-acd6-74c9467f4e31",
  "parentpageid": "d1d4ad37-367c-46d7-8406-9d3b943d7d08",
  "partialurl": "Provider-Map",
  "isroot": false,
  "rootwebpageid": "081faf1f-4c74-9ecc-889b-8843621e22d3",
  "title": "Provider Map",
  "summary": "<p>This is a sample landing page designed to be a starting point for your website</p>",
  "copy": "<div class="row sectionBlockLayout sectionPrimaryColor text-start"
  style="display: flex; flex-wrap: wrap; height: 15px; padding: 8px; margin: 0px;">
  <div class="container" style="display: flex; flex-wrap: wrap;"></div>
</div>
<div class="row sectionBlockLayout"
  style="display: flex; flex-wrap: wrap; margin: 0px; text-align: center; min-height: auto; padding: 8px;">
  <div class="container" style="display: flex; flex-wrap: wrap;">
    <div class="col-lg-4 columnBlockLayout left-pane"
      style="flex-grow: 1; min-width: 250px; display: flex; flex-direction: column; margin-left: 0px; margin-right: 0px;">
      <h3 class="pane-title">Provider List</h3>        
        <ul id="provider-list"></ul>
    </div>
    <div class="col-lg-8 columnBlockLayout"
      style="flex-grow: 1; min-width: 250px; display: flex; flex-direction: column; margin-left: 0px; margin-right: 0px;">
      <h3>Provider Map&nbsp;</h3>
      <div class="map-container">
        <div id="medical-map"></div>
      </div>
    </div>
  </div>
</div>


<script src="/js/maps.js"></script>
<script async defer
  src="https://maps.googleapis.com/maps/api/js?key=API_KEY&callback=initMap">
</script>",
  "publishingstateid": "9a28e01e-6995-4f47-91ee-d3be440d65cd",
  "enablerating": false,
  "enabletracking": false,
  "excludefromsearch": false,
  "hiddenfromsitemap": true,
  "sharedpageconfiguration": false,
  "feedbackpolicy": 756150000,
  "customjavascript": "(function() {
    const script = document.createElement("script");
    script.src = "https://maps.googleapis.com/maps/api/js?key=AIzaSyBwkFUa6pGauZUeV2lqfZ4d7w-MJYZ9-Dk&libraries=places&callback=initPowerPagesMap";
    script.async = true;
    script.defer = true;
    document.head.appendChild(script);

    const providers = [
        { id: 1, name: "Alice Johnson", address: "100 E Pratt St, Baltimore, MD 21202", lat: 39.2875, lng: -76.6122 },
        { id: 2, name: "Robert Smith", address: "7316 Wisconsin Ave, Bethesda, MD 20814", lat: 38.9831, lng: -77.0945 },
        { id: 3, name: "Maria Garcia", address: "8515 Georgia Ave, Silver Spring, MD 20910", lat: 38.9969, lng: -77.0269 },
        { id: 4, name: "James Wilson", address: "121 Cathedral St, Annapolis, MD 21401", lat: 38.9781, lng: -76.4952 }
    ];

    let map, placesService, distanceService, infoWindow;
    let markersArray = [];

    window.initPowerPagesMap = function() {
        map = new google.maps.Map(document.getElementById("medical-map"), {
            center: { lat: 39.0458, lng: -76.6413 }, 
            zoom: 9,
            mapTypeControl: false,
        });

        placesService = new google.maps.places.PlacesService(map);
        distanceService = new google.maps.DistanceMatrixService();
        infoWindow = new google.maps.InfoWindow();

        renderProviderList();
    };

    // 4. Render the Left Pane List
    function renderProviderList() {
        const listEl = document.getElementById("provider-list");
        providers.forEach(provider => {
            const li = document.createElement("li");
            li.className = "provider-item";
            li.innerHTML = `
                <div class="provider-name">${provider.name}</div>
                <div class="provider-address">${provider.address}</div>
            `;
            li.addEventListener("click", () => handleProviderClick(provider));
            listEl.appendChild(li);
        });
    }

    function handleProviderClick(provider) {
        clearMarkers();
        const originLocation = new google.maps.LatLng(provider.lat, provider.lng);
        
        map.setCenter(originLocation);
        map.setZoom(11);

        const originMarker = new google.maps.Marker({
            position: originLocation,
            map: map,
            title: provider.name,
            icon: "http://maps.google.com/mapfiles/ms/icons/blue-dot.png" 
        });
        markersArray.push(originMarker);

        placesService.nearbySearch({
            location: originLocation,
            radius: 20000, 
            type: "hospital" 
        }, (results, status) => {
            if (status === google.maps.places.PlacesServiceStatus.OK && results) {                
                filterByDriveTime(originLocation, results);
            }
        });
    }

   
    function filterByDriveTime(originLocation, placesResults) {
        const destinations = placesResults.map(place => place.geometry.location);

        distanceService.getDistanceMatrix({
            origins: [originLocation],
            destinations: destinations,
            travelMode: google.maps.TravelMode.DRIVING
        }, (response, status) => {
            if (status === google.maps.DistanceMatrixStatus.OK) {
                const resultsRow = response.rows[0].elements;
                
                for (let i = 0; i < resultsRow.length; i++) {
                    const element = resultsRow[i];                    
                    if (element.status === "OK" && element.duration.value <= 1800) {
                        createFacilityMarker(placesResults[i], element.duration.text);
                    }
                }
            }
        });
    }

    function createFacilityMarker(place, driveTimeText) {
        if (!place.geometry || !place.geometry.location) return;

        const marker = new google.maps.Marker({
            map: map,
            position: place.geometry.location,
            title: place.name,
            icon: "http://maps.google.com/mapfiles/ms/icons/red-dot.png"
        });
        markersArray.push(marker);

        google.maps.event.addListener(marker, "click", () => {
            infoWindow.setContent(`
                <div style="color: #333; font-family: sans-serif; padding: 5px;">
                    <strong style="font-size: 14px;">${place.name}</strong><br>
                    <span style="font-size: 12px; color: #666;">${place.vicinity}</span><br>
                    <div style="margin-top: 8px; font-size: 13px; color: #0078d4;">
                        <strong>Drive Time:</strong> ${driveTimeText}
                    </div>
                </div>
            `);
            infoWindow.open(map, marker);
        });
    }

    function clearMarkers() {
        markersArray.forEach(m => m.setMap(null));
        markersArray = [];
    }
})();

//REACT_APP_GOOGLE_MAPS_API_KEY = "AIzaSyBwkFUa6pGauZUeV2lqfZ4d7w-MJYZ9-Dk"
//REACT_APP_GOOGLE_SITE_KEY = 6Le5RqkhAAAAAJ2zZjLYyUBkJHoAaD9Or7O7ATpK"
}
